import React from 'react';
import { useGameStore } from '../store/gameStore';

export default function HUD() {
  const { timeRemaining, exp, maxExp, level, playerHp, playerMaxHp } = useGameStore();

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60);
    const s = seconds % 60;
    return `${m}:${s.toString().padStart(2, '0')}`;
  };

  const expPercent = Math.min(100, Math.max(0, (exp / maxExp) * 100));
  const hpPercent = Math.min(100, Math.max(0, (playerHp / playerMaxHp) * 100));

  return (
    <div className="absolute inset-0 pointer-events-none z-10 flex flex-col p-4">
      {/* 顶部经验条与倒计时 */}
      <div className="flex flex-col items-center w-full max-w-2xl mx-auto space-y-4">

        {/* 倒计时警示 */}
        <div className={`text-4xl font-extrabold px-6 py-2 rounded-2xl border-4 border-[#333333] shadow-[4px_4px_0px_0px_#333333] 
          ${timeRemaining <= 10 ? 'bg-[#FF5C77] text-white animate-pulse' : 'bg-[#FDFBF7] text-[#333333]'}`}
        >
          {formatTime(timeRemaining)}
        </div>

        {/* 经验条 */}
        <div className="w-full flex items-center space-x-4 bg-[#FDFBF7] p-2 rounded-full border-4 border-[#333333] shadow-[4px_4px_0px_0px_#333333]">
          <div className="font-bold text-[#333333] px-2 whitespace-nowrap">Lv.{level}</div>
          <div className="flex-1 h-6 bg-[#E5E0D8] rounded-full overflow-hidden border-2 border-[#333333]">
            <div 
              className="h-full bg-[#42D6A4] transition-all duration-300 ease-out" 
              style={{ width: `${expPercent}%` }}
            />
          </div>
        </div>

      </div>

      {/* 底部血条 (稍微偏移，或者放在左上角) */}
      <div className="mt-auto mb-8 w-64 mx-auto flex flex-col items-center bg-[#FDFBF7] p-2 rounded-2xl border-4 border-[#333333] shadow-[4px_4px_0px_0px_#333333]">
        <div className="w-full flex justify-between text-sm font-bold text-[#333333] mb-1 px-1">
          <span>HP</span>
          <span>{Math.ceil(playerHp)} / {playerMaxHp}</span>
        </div>
        <div className="w-full h-4 bg-[#E5E0D8] rounded-full overflow-hidden border-2 border-[#333333]">
          <div 
            className="h-full bg-[#FF5C77] transition-all duration-200"
            style={{ width: `${hpPercent}%` }}
          />
        </div>
      </div>
    </div>
  );
}

import React, { useEffect } from 'react';
import { useGameStore, UpgradeOption } from '../store/gameStore';

export default function UpgradeModal() {
  const { applyUpgrade, setPendingUpgrades, pendingUpgrades } = useGameStore();

  useEffect(() => {
    // 每次弹出时，随机生成3个选项
    const allOptions: UpgradeOption[] = ['attack_speed', 'attack_damage', 'move_speed'];
    const generated: UpgradeOption[] = [];
    for (let i = 0; i < 3; i++) {
      generated.push(allOptions[Math.floor(Math.random() * allOptions.length)]);
    }
    setPendingUpgrades(generated);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleSelect = (option: UpgradeOption) => {
    applyUpgrade(option);
  };

  const getOptionText = (opt: UpgradeOption) => {
    switch (opt) {
      case 'attack_speed': return { title: '攻击速度', desc: '攻击间隔减少 20%' };
      case 'attack_damage': return { title: '攻击伤害', desc: '基础伤害 + 5' };
      case 'move_speed': return { title: '移动速度', desc: '移速提升 10%' };
    }
  };

  if (pendingUpgrades.length === 0) return null;

  return (
    <div className="absolute inset-0 bg-[#333333]/80 flex flex-col items-center justify-center z-50 backdrop-blur-sm p-4">
      <h2 className="text-4xl font-extrabold text-[#FDFBF7] mb-8 drop-shadow-md">等级提升！</h2>

      <div className="flex flex-col md:flex-row gap-6 w-full max-w-4xl justify-center items-stretch">
        {pendingUpgrades.map((opt, idx) => {
          const { title, desc } = getOptionText(opt);
          return (
            <button 
              key={idx}
              onClick={() => handleSelect(opt)}
              className="flex-1 min-h-[200px] bg-[#FDFBF7] rounded-3xl p-6 flex flex-col items-center justify-center
                         border-4 border-[#333333] shadow-[8px_8px_0px_0px_#333333] 
                         active:translate-y-2 active:shadow-none transition-all hover:scale-105 hover:bg-[#42D6A4] group"
            >
              <h3 className="text-2xl font-extrabold text-[#333333] mb-4 group-hover:text-white transition-colors">{title}</h3>
              <p className="text-[#666666] font-bold group-hover:text-[#FDFBF7] transition-colors">{desc}</p>
            </button>
          );
        })}
      </div>
    </div>
  );
}

