private handleMouseClick() {
    if (!this.isGameStarted || this.isGameOver || this.isPaused) return;

    const store = useGameStore.getState();
    const now = this.time.now;

    // 攻击冷却检查
    if (now < this.lastShotTime + store.attackSpeed) return;
    this.lastShotTime = now;

    // 获取鼠标世界坐标
    const worldPoint = this.cameras.main.getWorldPoint(this.mousePointer.x, this.mousePointer.y);
    const angle = PhaserMath.Angle.Between(this.player.x, this.player.y, worldPoint.x, worldPoint.y);

    // 发射攻击（简化版：直接命中鼠标方向上的敌人）
    // 找到鼠标方向上最近的敌人
    let targetEnemy: Physics.Arcade.Sprite | null = null;
    let minDist = Number.MAX_VALUE;

    this.enemies.getChildren().forEach((child) => {
        const enemy = child as Physics.Arcade.Sprite;
        if (!enemy || !enemy.active) return;

        const enemyAngle = PhaserMath.Angle.Between(this.player.x, this.player.y, enemy.x, enemy.y);
        const angleDiff = Math.abs(PhaserMath.Angle.Wrap(enemyAngle - angle));

        // 只攻击鼠标方向锥形范围内的敌人（±30度）
        if (angleDiff < Math.PI / 6) {
            const dist = PhaserMath.Distance.Between(this.player.x, this.player.y, enemy.x, enemy.y);
            if (dist < 400 && dist < minDist) {
                minDist = dist;
                targetEnemy = enemy;
            }
        }
    });

    if (targetEnemy) {
        const damage = store.attackDamage;
        const enemy = targetEnemy as Physics.Arcade.Sprite;

        // 播放特效
        const fx = this.add.image(enemy.x, enemy.y, 'fx_hit');
        fx.setDepth(15);
        this.time.delayedCall(150, () => fx.destroy());

        // 扣血
        const hp = enemy.getData('hp') - damage;
        if (hp <= 0) {
            // 掉落经验
            this.dropGem(enemy.x, enemy.y);
            enemy.destroy();
        } else {
            enemy.setData('hp', hp);
            // 闪红
            enemy.setTint(0xff5c77);
            this.time.delayedCall(100, () => {
                if (enemy && enemy.active) enemy.clearTint();
            });
        }
    }
}

data.new_str:
private handleMouseClick() {
    if (!this.isGameStarted || this.isGameOver || this.isPaused) return;

    // 获取鼠标世界坐标，更新当前射击朝向
    const worldPoint = this.cameras.main.getWorldPoint(this.mousePointer.x, this.mousePointer.y);
    this.currentShootAngle = PhaserMath.Angle.Between(this.player.x, this.player.y, worldPoint.x, worldPoint.y);
}

private fireBullets() {
    const store = useGameStore.getState();
    const count = store.multiShotCount;
    const damage = store.attackDamage;
    const baseAngle = this.currentShootAngle;
    const speed = 400; // 子弹速度

    // 连发机制：如果是多发，在基础角度两侧展开
    const spreadAngle = Math.PI / 12; // 每发之间的角度间隔 (15度)
    const startAngle = baseAngle - ((count - 1) / 2) * spreadAngle;

    for (let i = 0; i < count; i++) {
        const angle = startAngle + i * spreadAngle;

        // 使用 fx_hit 作为子弹图，缩放一下
        const bullet = this.bullets.create(this.player.x, this.player.y, 'fx_hit') as Physics.Arcade.Sprite;
        bullet.setScale(0.5);
        bullet.setData('damage', damage);
        bullet.setDepth(6);

        const body = bullet.body as Physics.Arcade.Body;
        body.setSize(10, 10);
        body.setVelocity(Math.cos(angle) * speed, Math.sin(angle) * speed);

        // 子弹存活时间 (飞行一段距离后销毁)
        this.time.delayedCall(1500, () => {
            if (bullet && bullet.active) bullet.destroy();
        });
    }
}

private handleBulletEnemyCollision(b: any, e: any) {
    if (this.isGameOver || this.isPaused) return;

    const bullet = b as Physics.Arcade.Sprite;
    const enemy = e as Physics.Arcade.Sprite;

    const damage = bullet.getData('damage');
    bullet.destroy(); // 击中销毁

    const hp = enemy.getData('hp') - damage;
    if (hp <= 0) {
        this.dropGem(enemy.x, enemy.y);
        enemy.destroy();
    } else {
        enemy.setData('hp', hp);
        enemy.setTint(0xff5c77);
        this.time.delayedCall(100, () => {
            if (enemy && enemy.active) enemy.clearTint();
        });
    }
}

