private createParticles(x: number, y: number, color: number) {
    // 简易的自爆/登场粒子特效，使用已经 preload 好的 fx_hit 作为贴图
    const emitter = this.add.particles(x, y, 'fx_hit', {
        speed: { min: 100, max: 300 },
        angle: { min: 0, max: 360 },
        scale: { start: 1, end: 0 },
        tint: color,
        blendMode: 'ADD',
        lifespan: 800,
        quantity: 30
    });
    emitter.setDepth(20);
    // 自动销毁
    this.time.delayedCall(1000, () => {
        emitter.destroy();
    });
}

